import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as i,c as l,a as e,b as t,f as a,e as c}from"./app-3a3df056.js";const r={},d=e("p",null,[t("Analizando el ajuste de un modelo lineal simple utilizando la funcion "),e("code",null,"plot()")],-1),h=e("p",null,"Residuos vs Estimados:",-1),m=e("div",{class:"language-text line-numbers-mode","data-ext":"text"},[e("pre",{r:"",class:"language-text"},[e("code",null,`model1 <- lm(log(population_c1) ~ log(diameter_c1), data=planets_df_c)

plot(model1, 1)
`)]),e("div",{class:"line-numbers","aria-hidden":"true"},[e("div",{class:"line-number"}),e("div",{class:"line-number"}),e("div",{class:"line-number"})])],-1),u=e("p",null,"Me percato que la función plot para mi sorpresa podía recibir distintos parametros de entrada, dependiendo del primero de ellos.",-1),p=e("p",null,[t("Así es como llego a buscar la función plot de la libreria "),e("code",null,"graphics"),t(".")],-1),f=e("blockquote",null,[e("p",null,"Generic function for plotting of R objects. For simple scatter plots, plot.default will be used. However, there are plot methods for many R objects, including functions, data.frames, density objects, etc. Use methods(plot) and the documentation for these.")],-1),b={href:"http://adv-r.had.co.nz/",target:"_blank",rel:"noopener noreferrer"},g={href:"http://adv-r.had.co.nz/S3.html",target:"_blank",rel:"noopener noreferrer"},y=e("p",null,"R has three object oriented systems (plus the base types) Central to any object-oriented system are the concepts of class and method. A class defines the behaviour of objects by describing their attributes and their relationship to other classes. The class is also used when selecting methods, functions that behave differently depending on the class of their input. Classes are usually organised in a hierarchy: if a method does not exist for a child, then the parent’s method is used instead; the child inherits behaviour from the parent.",-1),v=e("p",null,"R’s three OO systems differ in how classes and methods are defined:",-1),_=e("p",null,'S3 implements a style of OO programming called generic-function OO. This is different from most programming languages, like Java, C++, and C#, which implement message-passing OO. With message-passing, messages (methods) are sent to objects and the object determines which function to call. Typically, this object has a special appearance in the method call, usually appearing before the name of the method/message: e.g., canvas.drawRect("blue"). S3 is different. While computations are still carried out via methods, a special type of function called a generic function decides which method to call, e.g., drawRect(canvas, "blue"). S3 is a very casual system. It has no formal definition of classes.',-1),w=e("p",null,"S4 works similarly to S3, but is more formal. There are two major differences to S3. S4 has formal class definitions, which describe the representation and inheritance for each class, and has special helper functions for defining generics and methods. S4 also has multiple dispatch, which means that generic functions can pick methods based on the class of any number of arguments, not just one.",-1),x=e("p",null,'Reference classes, called RC for short, are quite different from S3 and S4. RC implements message-passing OO, so methods belong to classes, not functions. $ is used to separate objects and methods, so method calls look like canvas$drawRect("blue"). RC objects are also mutable: they don’t use R’s usual copy-on-modify semantics, but are modified in place. This makes them harder to reason about, but allows them to solve problems that are difficult to solve with S3 or S4.',-1),j=e("p",null,"There’s also one other system that’s not quite OO, but it’s important to mention here:",-1),R=e("p",null,"base types, the internal C-level types that underlie the other OO systems. Base types are mostly manipulated using C code, but they’re important to know about because they provide the building blocks for the other OO systems. Only R-core can add new classes to this system, but it’s important to know about because it underpins the three other systems.",-1),k=e("p",null,"Generic functions and method dispatch Method dispatch starts with a generic function that decides which specific method to dispatch to. Generic functions all have the same form: a call to UseMethod that specifies the generic name and the object to dispatch on. This means that generic functions are usually very simple, like mean:",-1),O=e("div",{class:"language-text line-numbers-mode","data-ext":"text"},[e("pre",{r:"",class:"language-text"},[e("code",null,`mean <- function (x, ...) {
    UseMethod("mean", x)
}
`)]),e("div",{class:"line-numbers","aria-hidden":"true"},[e("div",{class:"line-number"}),e("div",{class:"line-number"}),e("div",{class:"line-number"})])],-1),S=c(`<p>Methods are ordinary functions that use a special naming convention: generic.class:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>mean.numeric &lt;- function(x, ...) sum(x) / length(x)
mean.data.frame &lt;- function(x, ...) sapply(x, mean, ...)
mean.matrix &lt;- function(x, ...) apply(x, 2, mean)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>type vs class</p><p>&#39;mode&#39; is a mutually exclusive classification of objects according to their basic structure. The &#39;atomic&#39; modes are numeric, complex, character and logical. Recursive objects have modes such as &#39;list&#39; or &#39;function&#39; or a few others. An object has one and only one mode.</p><p>&#39;class&#39; is a property assigned to an object that determines how generic functions operate with it. It is not a mutually exclusive classification. If an object has no specific class assigned to it, such as a simple numeric vector, it&#39;s class is usually the same as its mode, by convention.</p><p>typeof reveals the most fundamental datatype for R objects, going all the way down to the underlying C language datatypes in which R is implemented. So, it indicates how the variable is stored in the computer memory in terms of the lowest-level datatypes available in R. An object can only have one typeof type. The different possibilities can be found from help(typeof)</p><p>typeof is read-only whereas class is read-write. That is, we cannot directly change an object&#39;s typeof type; we must convert the underlying object into an object of a different type; indeed, there is no assignment allowed for typeof. In contrast, class allows assignment, which, for basic datatypes, converts the variable from one datatype to another. So, a variable&#39;s typeof can be changed by indirectly converting it by changing its class.</p>`,7);function T(C,A){const s=o("ExternalLinkIcon");return i(),l("div",null,[d,h,m,u,p,f,e("p",null,[t("Es como llego a este blog "),e("a",b,[t("Advanced R by Hadley Wickham"),a(s)]),t(" Donde en la seccion de "),e("a",g,[t("The S3 object system"),a(s)]),t(" describe las funciones genéricas de R y la sobrecarga de funciones:")]),y,v,_,w,x,j,R,k,O,S])}const M=n(r,[["render",T],["__file","r_generics.html.vue"]]);export{M as default};
